+  action?: "search" | "menu";
+}
+
+const tabs: TabItem[] = [
+  { id: "home", label: "Home", icon: Home, href: "/" },
+  { id: "bundles", label: "Bundles", icon: Package, href: "/bundles" },
+  { id: "search", label: "Search", icon: Search, action: "search" },
