+    light,
+    /** Medium tap feedback (20ms) */
+    medium,
+    /** Heavy tap feedback (30ms) */
+    heavy,
+    /** Success pattern (two quick taps) */
+    success,
+    /** Error pattern (three warning taps) */
+    error,
+    /** Selection feedback (10ms) */
+    selection,
+  };
+}
